import{_ as o,o as t,c as r,a0 as a}from"./chunks/framework.jwovEGr5.js";const m=JSON.parse('{"title":"Versioning & Deprecation Policy","description":"","frontmatter":{},"headers":[],"relativePath":"versioning.md","filePath":"versioning.md","lastUpdated":1784187737000}'),n={name:"versioning.md"};function i(s,e,c,d,l,p){return t(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="versioning-deprecation-policy" tabindex="-1">Versioning &amp; Deprecation Policy <a class="header-anchor" href="#versioning-deprecation-policy" aria-label="Permalink to &quot;Versioning &amp; Deprecation Policy&quot;">​</a></h1><h2 id="semantic-versioning" tabindex="-1">Semantic Versioning <a class="header-anchor" href="#semantic-versioning" aria-label="Permalink to &quot;Semantic Versioning&quot;">​</a></h2><p>This package follows <a href="https://semver.org/" target="_blank" rel="noreferrer">Semantic Versioning 2.0.0</a>:</p><ul><li><strong>MAJOR</strong> (<code>x.0.0</code>) — breaking changes to the public API: prop/event/method removal or signature changes, default-value changes that alter existing behavior, minimum Vue/ Node version bumps.</li><li><strong>MINOR</strong> (<code>1.x.0</code>) — new, backward-compatible functionality: new props/events/methods, new optional configuration.</li><li><strong>PATCH</strong> (<code>1.0.x</code>) — backward-compatible bug fixes, security fixes, documentation.</li></ul><p>Versions are cut via <code>release-it</code> (see <code>.release-it.json</code>), which derives the version bump and <code>CHANGELOG.md</code> entry from <a href="https://www.conventionalcommits.org/" target="_blank" rel="noreferrer">Conventional Commits</a> in the merged commit history — see <a href="https://github.com/enterprise/vue-iframe-wrapper/blob/main/CONTRIBUTING.md" target="_blank" rel="noreferrer"><code>CONTRIBUTING.md</code></a> for the commit message format.</p><h2 id="what-counts-as-the-public-api" tabindex="-1">What counts as the public API <a class="header-anchor" href="#what-counts-as-the-public-api" aria-label="Permalink to &quot;What counts as the public API&quot;">​</a></h2><p>Covered by SemVer guarantees:</p><ul><li><code>&lt;IframeWrapper /&gt;</code> props, events, and exposed instance methods (see <a href="/api/parameters">Parameters</a>)</li><li><code>useIframeInjection</code> and its return shape</li><li>The exported utility functions (<code>normaliseArray</code>, <code>createInjectionId</code>, <code>getSameOriginDocument</code>, <code>inject*IntoDocument</code>, etc.)</li><li>All exported types in <code>src/types/iframe.ts</code></li><li>The <code>./style.css</code> subpath export</li></ul><p><strong>Not</strong> covered (may change in a minor/patch release without notice):</p><ul><li>Internal DOM structure of injected elements beyond what&#39;s documented (e.g. don&#39;t rely on the exact <code>data-viw-id</code> attribute format persisting byte-for-byte)</li><li>Anything under <code>demo/</code> — it&#39;s a reference implementation, not a published artifact</li><li>Internal file/module layout under <code>src/</code> beyond the documented public exports in <code>src/index.ts</code></li></ul><h2 id="deprecation-process" tabindex="-1">Deprecation process <a class="header-anchor" href="#deprecation-process" aria-label="Permalink to &quot;Deprecation process&quot;">​</a></h2><p>When a public API needs to be removed or changed incompatibly:</p><ol><li><strong>Announce</strong> — the deprecated API is marked with a <code>@deprecated</code> TSDoc tag (visible in editor tooltips) and called out in the <code>CHANGELOG.md</code> entry for the minor release that introduces the replacement.</li><li><strong>Coexist</strong> — the deprecated API continues to work, unchanged, for at least one full minor version cycle. A console warning may be added (behind a check that avoids spamming logs in production, e.g. <code>if (import.meta.env.DEV)</code>).</li><li><strong>Remove</strong> — the deprecated API is removed only in the next <strong>major</strong> version, with the removal called out explicitly at the top of that major&#39;s changelog/release notes, including a migration snippet.</li></ol><p>Minimum deprecation window: <strong>one minor release</strong>, but for anything with wide observed usage, maintainers should prefer holding it longer rather than rushing the removal into the next major.</p><h2 id="supported-version-window" tabindex="-1">Supported version window <a class="header-anchor" href="#supported-version-window" aria-label="Permalink to &quot;Supported version window&quot;">​</a></h2><p>Per <a href="https://github.com/enterprise/vue-iframe-wrapper/blob/main/SECURITY.md" target="_blank" rel="noreferrer"><code>SECURITY.md</code></a>, only the latest minor of the current major version receives security patches by default. General bug fixes are typically only applied to the latest release; if your organization needs backports to an older major, that&#39;s a conversation for a dedicated support agreement rather than the default open-source support model.</p><h2 id="pre-1-0-note" tabindex="-1">Pre-1.0 note <a class="header-anchor" href="#pre-1-0-note" aria-label="Permalink to &quot;Pre-1.0 note&quot;">​</a></h2><p>This policy describes the intended behavior from <code>1.0.0</code> onward. There is no <code>0.x</code> history for this package to reconcile against.</p>',18)])])}const u=o(n,[["render",i]]);export{m as __pageData,u as default};
